+  VM_Version::VM_Features retval;
+  const char *str_orig = str;
+  for (int idx = 0;; ++idx) {
+    static_assert(sizeof(uint64_t) == sizeof(unsigned long long), "unexpected arch");
+    char *endptr;
+    errno = 0;
+    uint64_t u64 = strtoull(str, &endptr, 0);
