+  bool ok = true;
+
+  ResourceMark rm;
+  GrowableArray<int> boot_classpath_fds = ClassLoader::get_classpath_entry_fds();
+  GrowableArray<int> patch_module_fds = ClassLoader::get_patch_module_entry_fds();
+
+  for (int i = 0; i < fds.len(); ++i) {
+    if (fds.get_state(i) == FdsInfo::CLOSED) {
+      continue;
+    }
+    int fd = fds.get_fd(i);
+
+    char detailsbuf[PATH_MAX];
+    struct stat* st = fds.get_stat(i);
+    const char* type = stat2strtype(st->st_mode);
+    int linkret = readfdlink(fd, detailsbuf, sizeof(detailsbuf));
+    const char* details = 0 < linkret ? detailsbuf : "";
+    {
+      sockaddr_in sa;
+      socklen_t slen = sizeof(sa);
+      if (S_ISSOCK(st->st_mode) && 0 == getsockname(fd, (sockaddr*)&sa, &slen)) {
+        const size_t len = strlen(detailsbuf);
+        os::snprintf_checked(detailsbuf + len, sizeof(detailsbuf) - len, ",port=%d", (int)ntohs(sa.sin_port));
+      }
+    }
+    print_resources("JVM: FD fd=%d type=%s path=\"%s\" ", fd, type, details);
+
+    if (is_claimed_fd(fd)) {
+      print_resources("OK: claimed by java code\n");
+      continue;
+    }
+
+    if (_vm_inited_fds.find_state(fd, FdsInfo::CLOSED) != FdsInfo::CLOSED) {
+      print_resources("OK: inherited from process env\n");
+      continue;
+    }
+
+    if (S_ISSOCK(st->st_mode)) {
+      if (is_socket_from_jcmd(fd)){
+        print_resources("OK: jcmd socket\n");
+        continue;
+      }
+    }
+
+    if (boot_classpath_fds.contains(fd)) {
+      print_resources("OK: claimed by classloader\n");
+      continue;
+    }
+
+    if (patch_module_fds.contains(fd)) {
+      print_resources("OK: claimed by patch-module\n");
+      continue;
+    }
+
+    if (!strncmp(details, "/memfd:", 7)) {
+      print_resources("OK: memfd\n");
+      continue;
+    }
+
+    if (CRaCAllowedOpenFilePrefixes != nullptr) {
+      const char *prefix = CRaCAllowedOpenFilePrefixes;
+      // JDK appends to ccstrlist using newline, on command line that would be comma
+      size_t prefix_length = strcspn(prefix, ",\n");
+      bool matched = false;
+      while (prefix_length > 0) {
+        if (!strncmp(details, prefix, prefix_length)) {
+          matched = true;
+          break;
+        }
+        if (prefix[prefix_length] == '\0') {
+          break;
+        }
+        prefix += prefix_length + 1;
+        prefix_length = strcspn(prefix, ",\n");
+      }
+      if (matched) {
+        print_resources("OK: allowed in -XX:CRaCAllowedOpenFilePrefixes\n");
+        continue;
+      }
+    }
+
+    print_resources("BAD: opened by application\n");
+    ok = false;
+
+    const int maxinfo = 64;
+    size_t buflen = strlen(details) + maxinfo;
+    char* msg = NEW_C_HEAP_ARRAY(char, buflen, mtInternal);
+    int len = os::snprintf(msg, buflen, "FD fd=%d type=%s path=%s", fd, type, detailsbuf);
+    msg[len < 0 ? 0 : ((size_t) len >= buflen ? buflen - 1 : len)] = '\0';
+    _failures->append(CracFailDep(stat2stfail(st->st_mode & S_IFMT), msg));
+  }
+
+  return ok;
+}
