+
+static char modules_path[JVM_MAXPATHLEN] = { '\0' };
+
+static bool is_fd_ignored(int fd, const char *path) {
+  const char *list = CRaCIgnoredFileDescriptors;
+  while (list && *list) {
+    const char *end = strchr(list, ',');
+    if (!end) {
+      end = list + strlen(list);
+    }
+    char *invalid;
+    int ignored_fd = strtol(list, &invalid, 10);
+    if (invalid == end) { // entry was integer -> file descriptor
+      if (fd == ignored_fd) {
+        log_trace(os)("CRaC not closing file descriptor %d (%s) as it is marked as ignored.", fd, path);
+        return true;
+      }
+    } else { // interpret entry as path
+      int path_len = path ? strlen(path) : -1;
+      if (path_len != -1 && path_len == end - list && !strncmp(path, list, end - list)) {
+        log_trace(os)("CRaC not closing file descriptor %d (%s) as it is marked as ignored.", fd, path);
+        return true;
+      }
+    }
+    if (*end) {
+      list = end + 1;
+    } else {
+      break;
+    }
+  }
+
+  if (os::same_files(modules_path, path)) {
+    // Path to the modules directory is opened early when JVM is booted up and won't be closed.
+    // We can ignore this for purposes of CRaC.
+    return true;
+  }
+
+  if (LogConfiguration::is_fd_used(fd)) {
+    return true;
+  }
+
+  if (defaultStream::instance->is_fd_used(fd)) {
+    return true;
+  }
+
+  return false;
+}
+
+static void close_extra_descriptors() {
+  // Path to the modules directory is opened early when JVM is booted up and won't be closed.
+  // We can ignore this for purposes of CRaC.
+  if (modules_path[0] == '\0') {
+    const char* fileSep = os::file_separator();
+    jio_snprintf(modules_path, JVM_MAXPATHLEN, "%s%slib%s" MODULES_IMAGE_NAME, Arguments::get_java_home(), fileSep, fileSep);
+  }
+
+  char path[PATH_MAX];
+  struct dirent *dp;
+
+  DIR *dir = opendir("/proc/self/fd");
+  while ((dp = readdir(dir))) {
+    int fd = atoi(dp->d_name);
+    if (fd > 2 && fd != dirfd(dir)) {
+      int r = readfdlink(fd, path, sizeof(path));
+      if (!is_fd_ignored(fd, r != -1 ? path : nullptr)) {
+        log_warning(os)("CRaC closing file descriptor %d: %s", fd, path);
+        close(fd);
+      }
+    }
+  }
+  closedir(dir);
+}
+
+void crac::vm_create_start() {
+  if (!CRaCCheckpointTo) {
+    return;
+  }
+  close_extra_descriptors();
+  _vm_inited_fds.initialize();
+}
+
+static bool read_all(int fd, const char *filename, char *dest, size_t n) {
+  size_t rd = 0;
+  do {
+    ssize_t r = ::read(fd, dest + rd, n - rd);
+    if (r == 0) {
+      log_error(crac)("Unexpected end of file %s (read %zu/%zu bytes)", filename, rd, n);
+      return false;
+    } else if (r < 0) {
+      if (errno == EINTR) {
+        continue;
+      }
+      log_error(crac)("I/O error reading %s: %s", filename, os::strerror(errno));
+      return false;
+    }
+    rd += r;
+  } while (rd < n);
+  return true;
+}
+
+// RAII object to close file descriptor
+class FDGuard {
+private:
+  const char *_what;
+  int _fd;
+public:
+  FDGuard(const char *what, int fd): _what(what), _fd(fd) {}
+  ~FDGuard() {
+    if (_fd >= 0 && ::close(_fd) != 0) {
+      log_error(crac)("Cannot close %s: %s", _what, os::strerror(errno));
+    }
+  }
+};
+
+bool crac::read_bootid(char *dest) {
+  const char *boot_id_file = "/proc/sys/kernel/random/boot_id";
+  int fd = ::open(boot_id_file, O_RDONLY);
+  FDGuard guard("system boot ID file", fd);
+  if (fd < 0 || !read_all(fd, boot_id_file, dest, UUID_LENGTH)) {
+    log_error(crac)("Cannot read system boot ID");
+    return false;
+  }
+  char c;
+  ssize_t r = ::read(fd, &c, 1);
+  if (r == 0) {
+    // Some systems don't end boot-id with a newline
+    return true;
+  } else if (r < 0) {
+    log_error(crac)("Failure reading system boot ID: %s", os::strerror(errno));
+    return false;
+  } else if (c != '\n') {
+    log_error(crac)("System boot ID does not end with a newline");
+    return false;
+  }
+  r = ::read(fd, &c, 1);
+  if (r == 0) {
+    return true;
+  } else if (r < 0) {
+    log_error(crac)("Error reading system boot ID: %s", os::strerror(errno));
+  } else { // r > 0
+    log_error(crac)("Unexpected data in system boot ID");
+  }
+  return false;
+}
+
+bool crac::random_bytes(u1 *dest, size_t length) {
+  const char *urandom_file = "/dev/urandom";
+  int fd = ::open(urandom_file, O_RDONLY);
+  FDGuard guard("/dev/urandom", fd);
+  if (fd < 0 || !read_all(fd, urandom_file, reinterpret_cast<char *>(dest), length)) {
+    log_error(crac)("Cannot get random bytes");
+    return false;
+  }
+  return true;
+}

