+  // Commit them back
+  if (capacity() < orig_capacity) {
+    expand(orig_capacity - capacity(), _workers);
+  }
+  assert(capacity() >= orig_capacity, "unexpectedly lost capacity: %zu -> %zu", orig_capacity, capacity());
+}

