+template<class T> class FutureRef {
+private:
+  T *_t;
+public:
+  FutureRef(T *t): _t(t) {}
+  ~FutureRef() {
+    delete _t;
+  }
+  T *operator->() {
+    return _t;
+  }
+  T *extract() {
+    T *tmp = _t;
+    _t = nullptr;
+    return tmp;
+  }
+};
