+#ifndef SHARE_RUNTIME_CRAC_ENGINE_HPP
+#define SHARE_RUNTIME_CRAC_ENGINE_HPP
+
+#include "crlib/crlib.h"
+#include "crlib/crlib_description.h"
+#include "crlib/crlib_image_constraints.h"
+#include "crlib/crlib_image_score.h"
