+#include "utilities/growableArray.hpp"
+
+#include <cstddef>
+#include <cstdint>
+
+// CRaC engine library wrapper.
+class CracEngine : public CHeapObj<mtInternal> {
+public:
+  static constexpr const size_t MAX_ENGINE_LENGTH = 128;
+
+  CracEngine(bool for_restore);
+  ~CracEngine();
+
+  CracEngine(const CracEngine &) = delete;
+  CracEngine &operator=(const CracEngine &) = delete;
+
+  // Use this to check whether the constructor succeeded.
+  bool is_initialized() const;
+
+  // Operations supported by all engines
+  int checkpoint() const;
+  int restore() const;
+  bool configure_image_location(const char *image_location);
+  GrowableArrayCHeap<const char *, MemTag::mtInternal> *vm_controlled_options() const;
+
+  // Optionally-supported operations
+
+  enum class ApiStatus : uint8_t { OK, ERR, UNSUPPORTED };
+
+  ApiStatus prepare_restore_data_api();
+  bool set_restore_data(const void *data, size_t size) const;
+  size_t get_restore_data(void *buf, size_t size) const;
+
+  ApiStatus prepare_description_api();
+  const char *description() const;
+  const char *configuration_doc() const;
+  const crlib_conf_option_t *configuration_options();
+
+  ApiStatus prepare_image_constraints_api();
+  bool set_label(const char* label, const char* value);
+  bool store_cpuinfo(const VM_Version::VM_Features *current_features) const;
+  void require_cpuinfo(const VM_Version::VM_Features *current_features, bool exact) const;
+  void check_cpuinfo(const VM_Version::VM_Features *current_features, bool exact) const;
+
+  ApiStatus prepare_image_score_api();
+  bool set_score(const char* metric, double value);
+
+private:
+  char _name[MAX_ENGINE_LENGTH];
+  void *_lib = nullptr;
+  crlib_api_t *_api = nullptr;
+  crlib_conf_t *_conf = nullptr;
+  char *_image_location = nullptr;
+
+  crlib_restore_data_t *_restore_data_api = nullptr;
+  crlib_description_t *_description_api = nullptr;
+  crlib_image_constraints_t *_image_constraints_api = nullptr;
+  crlib_image_score_t *_image_score_api = nullptr;
+
+  crlib_conf_option_t *_options = nullptr;
+};
+
+#endif // SHARE_RUNTIME_CRAC_ENGINE_HPP

