+static bool parse_bool(const char* str, Option<bool>* result) {
+  if (strcmp(str, "true") == 0) {
+    *result = {true, false};
+    return true;
+  }
+  if (strcmp(str, "false") == 0) {
+    *result = {false, false};
+    return true;
+  }
+  LOG("expected '%s' to be either 'true' or 'false'", str);
+  return false;
