+#ifdef LINUX
+
+#define RESTORE_SIGNAL (SIGRTMIN + 2)
+
+int kickjvm(pid_t jvm, int code) {
+    union sigval sv = { .sival_int = code };
+    if (-1 == sigqueue(jvm, RESTORE_SIGNAL, sv)) {
+        LOG("sigqueue: %s", strerror(errno));
+        return 1;
+    }
+    return 0;
+}
