+int waitjvm() {
+    siginfo_t info;
+    sigset_t waitmask;
+    sigemptyset(&waitmask);
+    sigaddset(&waitmask, RESTORE_SIGNAL);
+
+    int sig;
+    do {
+        sig = sigwaitinfo(&waitmask, &info);
+    } while (sig == -1 && errno == EINTR);
+
+    if (info.si_code != SI_QUEUE) {
+        return -1;
+    }
+    return info.si_int;
+}
