+{
+    jint extensionEventCount = 0;
+    jvmtiExtensionEventInfo* extensionEvents = NULL;
+    jvmtiError err = (*jvmti)->GetExtensionEvents(jvmti, &extensionEventCount, &extensionEvents);
+    if (JVMTI_ERROR_NONE != err) {
