+ * @summary The test checks that process PID is adjusted with the specified value, when checkpointing in a container. Default min PID value is 128.
+ * @requires (os.family == "linux")
+ * @requires container.support
+ * @comment Static JDK eagerly loads X11 which is missing from the Docker image
+ * @requires !jdk.static
+ * @library /test/lib
+ * @modules java.base/jdk.internal.platform
+ * @build ContainerPidAdjustmentTest
+ * @run driver/timeout=120 jdk.test.lib.crac.CracTest  true   false  INF     true   128
+ * @run driver/timeout=120 jdk.test.lib.crac.CracTest  true   true   1       false  1
+ * @run driver/timeout=120 jdk.test.lib.crac.CracTest  true   true   100     true   100
+ * @run driver/timeout=120 jdk.test.lib.crac.CracTest  false  false  INF     false  1
+ * @run driver/timeout=120 jdk.test.lib.crac.CracTest  false  true   1       false  1
+ * @run driver/timeout=120 jdk.test.lib.crac.CracTest  false  true   1       true   1
+ * @run driver/timeout=120 jdk.test.lib.crac.CracTest  false  true   200     true   200
+ * @run driver/timeout=120 jdk.test.lib.crac.CracTest  false  true   1000    false  1000
+ * @run driver/timeout=120 jdk.test.lib.crac.CracTest  false  true   2000    true   2000   1000
+ * @run driver/timeout=120 jdk.test.lib.crac.CracTest  false  true   0       true   -1
+ * @run driver/timeout=120 jdk.test.lib.crac.CracTest  false  true   -10     true   -1
+ * @run driver/timeout=120 jdk.test.lib.crac.CracTest  false  true   blabla  true   -1
+ * @run driver/timeout=120 jdk.test.lib.crac.CracTest  false  true   5000000 true   -1
+ * @run driver/timeout=120 jdk.test.lib.crac.CracTest  false  true   5000000 true   -1     MAX-100
+ * @run driver/timeout=120 jdk.test.lib.crac.CracTest  false  true   MAX-1   true   -1
+ */
+public class ContainerPidAdjustmentTest implements CracTest {
+    @CracTestArg(0)
+    boolean runDirectly;
+
+    @CracTestArg(1)
+    boolean needSetMinPid;
+
+    @CracTestArg(2)
+    String lastPid;
+
+    @CracTestArg(3)
+    boolean usePrivilegedContainer;
+
+    @CracTestArg(4)
+    long expectedLastPid;
+
+    @CracTestArg(value = 5, optional = true)
+    String lastPidSetup;
+
+    final private String CURRENT_PID_MESSAGE = "Current PID = ";
+    final private String MAX_PID_PREFIX = "MAX";
+
+    @Override
+    public void test() throws Exception {
+        final String imageName = Common.imageName("pid-adjustment");
+        CracContainerBuilder builder = new CracContainerBuilder()
+            .engine(CracEngine.CRIU)
+            .inDockerImage(imageName)
+            .runContainerDirectly(runDirectly)
+            .containerUsePrivileged(usePrivilegedContainer);
+        try {
+            if (needSetMinPid) {
+                builder.vmOption("-XX:CRaCMinPid=" + createLastPidValue(lastPid));
+            }
+            if (null != lastPidSetup) {
+                // Set up the initial last pid,
+                // create a non-privileged user,
+                // and force spinning the last pid running checkpoint under the user.
+                String setupLastPidCmd = "export LAST_PID=" + createLastPidValue(lastPidSetup)
+                        + " && echo ${LAST_PID} >/proc/sys/kernel/ns_last_pid";
+                if (Platform.isMusl()) {
+                    builder.containerSetup("sh", "-x", "-c",
+                            "adduser -D the_user && cat /proc/sys/kernel/pid_max && " + setupLastPidCmd);
+                } else {
+                    builder.containerSetup("bash", "-x", "-c",
+                            "useradd the_user && cat /proc/sys/kernel/pid_max && " + setupLastPidCmd);
+                }
+                builder.dockerCheckpointOptions("-u", "the_user");
+            }
+
+            if (0 < expectedLastPid) {
+                // Cannot use doCheckpoint because for CRIU it expects the process to be killed on checkpoint
+                try (var p = builder.startCheckpoint()) {
+                    p.waitForSuccess();
+                }
+            } else {
+                final int expectedExitValue = (int)java.lang.Math.abs(expectedLastPid);
+                OutputAnalyzer oa = builder.doCheckpointToAnalyze();
+                oa.shouldHaveExitValue(expectedExitValue).shouldNotContain(CURRENT_PID_MESSAGE);
+                if (null != lastPidSetup) {
+                    oa.shouldContain("spin_last_pid: Invalid argument (" + lastPid + ")");
+                }
+            }
+        } finally {
+            builder.ensureContainerKilled();
+        }
+    }
+
+    private String createLastPidValue(String expr) {
+        if (expr.startsWith(MAX_PID_PREFIX)){
+            expr = expr.substring(MAX_PID_PREFIX.length());
+            expr = "$(($(cat /proc/sys/kernel/pid_max)" + expr + "))";
+        }
+        return expr;
+    }
+
+    @Override
+    public void exec() throws Exception {
+        System.out.println(CURRENT_PID_MESSAGE + ProcessHandle.current().pid());
+        assertLessThan((long)0, expectedLastPid, "Shouldn't happen");
+        assertLessThan(expectedLastPid, ProcessHandle.current().pid());
+    }
+}

