+        serverThread.start();
+        SocketChannel clientChannel = SocketChannel.open(StandardProtocolFamily.UNIX);
+        assertTrue(clientChannel.connect(address));
+        latch1.await();
+        CRaCMXBean.getCRaCMXBean().checkpointRestore();
+        latch2.countDown();
+    }
+
