+ * @library /test/lib
+ * @build PollerTest
+ * @run driver/timeout=10 jdk.test.lib.crac.CracTest false 3
+ * @run driver/timeout=10 jdk.test.lib.crac.CracTest true  3
+ */
+public class PollerTest implements CracTest {
+    @CracTestArg(0)
+    boolean checkpointVirtual;
+
+    @CracTestArg(1)
+    String pollerMode;
+
+    @Override
+    public void test() throws Exception {
+        new CracBuilder()
+                .engine(CracEngine.SIMULATE)
+                .javaOption("jdk.pollerMode", pollerMode)
+                .doCheckpoint();
+    }
+
+    @FunctionalInterface
+    interface ThrowingRunnable {
+        public void run() throws Exception;
+    }
+
+    @Override
+    public void exec() throws Exception {
+        execInVirtual(this::useSockets);
+        CRaCMXBean bean = CRaCMXBean.getCRaCMXBean();
+        if (checkpointVirtual) {
+            execInVirtual(bean::checkpointRestore);
+        } else {
+            bean.checkpointRestore();
+        }
+        execInVirtual(this::useSockets);
+    }
+
+    public void execInVirtual(ThrowingRunnable runnable) throws Exception {
+        AtomicReference<Exception> ex = new AtomicReference<>();
+        Thread.startVirtualThread(() -> {
+            try {
+                runnable.run();
+            } catch (Exception e) {
+                ex.set(e);
+            }
+        }).join();
+        if (ex.get() != null) {
+            throw ex.get();
+        }
+    }
+
+    private void useSockets() throws IOException, InterruptedException {
+        ServerSocket serverSocket = new ServerSocket(0, 50, InetAddress.getLoopbackAddress());
+        Thread serverThread = Thread.startVirtualThread(() -> {
+            try {
+                Socket socket = serverSocket.accept();
+                socket.close();
+                // the socket leaks in here but for some reason it does not leave the FD open
+            } catch (IOException e) {
+                e.printStackTrace();
+            }
+        });
+        Socket clientSocket = new Socket(InetAddress.getLoopbackAddress(), serverSocket.getLocalPort());
+        clientSocket.close();
+        serverSocket.close();
+        serverThread.join();
+    }
+
+}

