+            readFully(channel, byteBuffer);
+            assertEquals("lo ", new String(buf2, StandardCharsets.UTF_8));
+
+            channel.position(8 * 1024 * 1024 + 6);
+            readFully(channel, byteBuffer);
+            assertEquals("wor", new String(buf2, StandardCharsets.UTF_8));
