+/*
+ * @test id=DEFAULT
+ * @summary a trivial test for SelectionKey's state after restore
+ * @library /test/lib
+ * @build KeyAfterRestoreTest
+ * @run driver/timeout=30 jdk.test.lib.crac.CracTest true
