+ */
+/*
+ * @test id=ALT_WINDOWS
+ * @requires (os.family == "windows")
+ * @library /test/lib
+ * @build KeyAfterRestoreTest
+ * @run driver/timeout=30 jdk.test.lib.crac.CracTest true sun.nio.ch.WindowsSelectorProvider
+ * @run driver/timeout=30 jdk.test.lib.crac.CracTest false sun.nio.ch.WindowsSelectorProvider
+ */
+public class KeyAfterRestoreTest implements CracTest {
+    @CracTestArg
+    boolean openSelectorAtFirst;
+
+    @CracTestArg(value = 1, optional = true)
+    String selectorImpl;
+
+    @Override
+    public void test() throws Exception {
+        CracBuilder builder = new CracBuilder().engine(CracEngine.SIMULATE);
+        if (selectorImpl != null) {
+            builder.javaOption(SelectorProvider.class.getName(), selectorImpl);
+        }
+        builder.doCheckpoint();
+    }
+
+    @Override
+    public void exec() throws Exception {
+        if (selectorImpl != null) {
+            assertEquals(selectorImpl, SelectorProvider.provider().getClass().getName());
+        }
+
+        ChannelResource ch;
+        Selector selector = null;
+
+        // check various order (see ZE-970)
+        if (openSelectorAtFirst) { selector = Selector.open(); }
+
+        ch = new ChannelResource();
+        ch.open();
+
+        if (!openSelectorAtFirst) { selector = Selector.open(); }
+
+        ch.register(selector);
+
+        CRaCMXBean.getCRaCMXBean().checkpointRestore();
+
+        Thread.sleep(200);
+
+        ch.checkKey();
+
+        selector.close();
+    }
+
+    static class ChannelResource implements Resource {
+
+        private SocketChannel channel;
+        private SelectionKey key;
+        private Selector selector;
+
+        private Object att = new Integer(123);
+
+        public ChannelResource() {
+            Context.getGlobalContext().register(this);
+        }
+
+        public void open() throws IOException {
+            channel = SocketChannel.open();
+            channel.configureBlocking(false);
+        }
+
+        public void register(Selector selector) throws IOException {
+            key = channel.register(selector, SelectionKey.OP_CONNECT);
+            key.attach(att);
+            this.selector = selector;
+        }
+
+        @Override
+        public void beforeCheckpoint(Context<? extends Resource> context) throws IOException {
+
+            channel.socket().close(); // close the channel => cancel the key
+            check(!channel.isOpen(), "the channel should not be open");
+            selector.select(100); // causes the channel deregistration
+        }
+
+        @Override
+        public void afterRestore(Context<? extends Resource> context) {
+
+            check(key.selector().equals(selector), "invalid key.selector()");
+            check(key.channel().equals(channel), "invalid key.channel()");
+
+            // the key is cancelled
+            check(!key.isValid(), "expected: key.isValid() == false");
+
+            boolean caught = false;
+            try {
+                key.readyOps();
+            } catch (CancelledKeyException e) {
+                caught = true;
+            }
+            check(caught, "expected CancelledKeyException is missing");
+
+            caught = false;
+            try {
+                key.interestOps();
+            } catch (CancelledKeyException e) {
+                caught = true;
+            }
+            check(caught, "expected CancelledKeyException is missing");
+
+            caught = false;
+            try {
+                key.interestOps(SelectionKey.OP_CONNECT);
+            } catch (CancelledKeyException e) {
+                caught = true;
+            }
+            check(caught, "expected CancelledKeyException is missing");
+
+            caught = false;
+            try {
+                key.readyOps();
+            } catch (CancelledKeyException e) {
+                caught = true;
+            }
+            check(caught, "expected CancelledKeyException is missing");
+
+            caught = false;
+            try {
+                key.isReadable();
+            } catch (CancelledKeyException e) {
+                caught = true;
+            }
+            check(caught, "expected CancelledKeyException is missing");
+
+            caught = false;
+            try {
+                key.isWritable();
+            } catch (CancelledKeyException e) {
+                caught = true;
+            }
+            check(caught, "expected CancelledKeyException is missing");
+
+            caught = false;
+            try {
+                key.isConnectable();
+            } catch (CancelledKeyException e) {
+                caught = true;
+            }
+            check(caught, "expected CancelledKeyException is missing");
+
+            caught = false;
+            try {
+                key.isAcceptable();
+            } catch (CancelledKeyException e) {
+                caught = true;
+            }
+            check(caught, "expected CancelledKeyException is missing");
+
+            check(att.equals(key.attachment()), "invalid key.attachment()");
+
+            key.cancel(); // try just in case
+
+            // register again
+            try {
+                channel = SocketChannel.open();
+                channel.configureBlocking(false);
+                key = channel.register(selector, SelectionKey.OP_READ);
+            } catch (Exception e) {
+                throw new RuntimeException(e);
+            }
+        }
+
+        // to check after restore
+        public void checkKey() {
+
+            check(key.isValid(), "key must be valid");
+
+            check(key.selector().equals(selector), "invalid key.selector()");
+            check(key.channel().equals(channel), "invalid key.channel()");
+
+            key.isReadable(); // just call, cannot set "ready" state manually
+            check(!key.isWritable(), "invalid key.isWritable()");
+            check(!key.isConnectable(), "invalid key.isConnectable()");
+            check(!key.isAcceptable(), "invalid key.isAcceptable()");
+
+            check(key.interestOps() == SelectionKey.OP_READ, "invalid key.interestOps()");
+
+            System.out.println(">> ready >> " + key.readyOps());
+
+            check(key.attachment() == null, "key.attachment() expected to be null");
+
+            key.cancel(); // try just in case
+        }
+
+        private void check(boolean b, String msg) {
+            if (!b) {
+                throw new RuntimeException(msg);
+            }
+        }
+    }
+}

