+ * @run driver jdk.test.lib.crac.CracTest true  true sun.nio.ch.PollSelectorProvider
+ */
+/*
+ * @test id=ALT_WINDOWS
+ * @requires (os.family == "windows")
+ * @library /test/lib
+ * @build MultipleSelectSingleCloseTest
+ * @run driver jdk.test.lib.crac.CracTest false false sun.nio.ch.WindowsSelectorProvider
+ * @run driver jdk.test.lib.crac.CracTest false true sun.nio.ch.WindowsSelectorProvider
+ * @run driver jdk.test.lib.crac.CracTest true  true sun.nio.ch.WindowsSelectorProvider
+ */
+public class MultipleSelectSingleCloseTest implements CracTest {
+    private final static Random RND = new Random();
+
+    @CracTestArg(0)
+    boolean skipCR;
+
+    @CracTestArg(1)
+    boolean closeBeforeCheckpoint;
+
+    @CracTestArg(value = 2, optional = true)
+    String selectorImpl;
+
+    @Override
+    public void test() throws Exception {
+        CracBuilder builder = new CracBuilder().engine(CracEngine.SIMULATE);
+        if (selectorImpl != null) {
+            builder.javaOption(SelectorProvider.class.getName(), selectorImpl);
+        }
+        if (skipCR) {
+            builder.doPlain();
+        } else {
+            builder.doCheckpoint();
+        }
+    }
+
+    @Override
+    public void exec() throws Exception {
+        if (selectorImpl != null) {
+            assertEquals(selectorImpl, SelectorProvider.provider().getClass().getName());
+        }
+
+        int nThreads = 20;
+
+        AtomicInteger nSelected = new AtomicInteger(0);
+
+        Selector selector = Selector.open();
+
+        Thread selectThreads[] = new Thread[nThreads];
+
+        Runnable rStart = new Runnable() {
+            @Override
+            public void run() {
+
+                for (int i = 0; i < nThreads; ++i) {
+
+                    selectThreads[i] = new Thread(new Runnable() {
+                        @Override
+                        public void run() {
+                            try {
+                                boolean timeout = RND.nextBoolean();
+                                int n = nSelected.incrementAndGet();
+                                System.out.println(">> select" + (timeout ? " (t)" : "") + " " + n);
+                                if (timeout) { selector.select(10 + RND.nextInt(7_000)); }
+                                else { selector.select(); }
+                                nSelected.decrementAndGet();
+                                System.out.println(">> done" + (timeout ? " (t)" : "") + " " + n);
+                            } catch (ClosedSelectorException e) {
+                                System.out.println(">> ClosedSelectorException"); // expected when the selector is closed
+                                nSelected.decrementAndGet();
+                            } catch (IOException e) {
+                                throw new RuntimeException(e);
+                            }
+                        }
+                    });
+                    selectThreads[i].start();
+                    try { Thread.sleep(50); } catch (InterruptedException ie) {}
+                }
+            }
+        };
+        Thread tStart = new Thread(rStart);
+        tStart.start();
+        Thread.sleep(500);
+
+        if (closeBeforeCheckpoint) {
+            tStart.join();
+            Thread.sleep(1000);
+            selector.close();
+        }
+
+        if (!skipCR) {
+            CRaCMXBean.getCRaCMXBean().checkpointRestore();
+        }
+
+        if (!closeBeforeCheckpoint) {
+            tStart.join();
+            Thread.sleep(1000);
+            selector.close();
+        }
+
+        do { Thread.sleep(2000); } while (nSelected.get() > 0);
+
+        if (nSelected.get() < 0) { throw new RuntimeException("negative nSelected??"); }
+
+        // just in case...
+        for (Thread t: selectThreads) { t.join(); }
+    }
+}

