+                // do nothing
+            }
+            if (exitCode == 0) {
+                System.err.println("Core dump seems to be created successfully for pid=" + pid);
+            } else {
+                System.err.println("Something went wrong while dumping pid=" + pid);
+            }
+        } catch (IOException | InterruptedException e) {
+            System.err.println("Exception thrown while dumping pid=" + pid);
+            e.printStackTrace();
+        }
+    }
+
+    public void clearPausePid() throws IOException {
+        assertEquals(CracEngine.PAUSE, engine, "Pause PID file is created only with pauseengine");
+        Files.delete(imageDir.resolve(PAUSE_PID_FILE));
+    }
